#include <stdio.h>
#include <riscv_vector.h>

#define N 64

int32_t a[N], b[N], c[N];

/* Simple vector add loop: c[i] = a[i] + b[i] */
void vadd_loop(int32_t *dst, const int32_t *src1, const int32_t *src2, int n) {
    while (n > 0) {
        size_t vl = __riscv_vsetvl_e32m4(n);
        vint32m4_t va = __riscv_vle32_v_i32m4(src1, vl);
        vint32m4_t vb = __riscv_vle32_v_i32m4(src2, vl);
        vint32m4_t vc = __riscv_vadd_vv_i32m4(va, vb, vl);
        __riscv_vse32_v_i32m4(dst, vc, vl);
        src1 += vl;
        src2 += vl;
        dst += vl;
        n -= vl;
    }
}

int main(void) {
    /* Init */
    for (int i = 0; i < N; i++) {
        a[i] = i;
        b[i] = N - i;
    }

    vadd_loop(c, a, b, N);

    /* Verify */
    int pass = 1;
    for (int i = 0; i < N; i++) {
        if (c[i] != N) { pass = 0; break; }
    }
    printf("vadd test: %s\n", pass ? "PASS" : "FAIL");
    return pass ? 0 : 1;
}

